h1, h2, h3 {
  font-weight: 600;
  line-height: 100%;
}

h1 {
  font-size: 98px;
}

h2 {
  font-size: 72px;
}

h3 {
  font-size: 32px;
}

p {
  font-weight: 400;
  font-size: 22px;
  line-height: 140%;
}

header {
  position: relative;
}

.gradient-bg {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 700px;
  background: linear-gradient(180deg, #78FF3A 0%, rgba(255, 255, 255, 0.00) 100%);
  z-index: -1;
}

header, footer {
  position: relative;
}

.gradient-bg-bottom {
  position: absolute;
  bottom: 0;
  left: 0;
  width: 100%;
  height: 292px;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.00) 0%, #78FF3A 100%);
  z-index: -1;
}
